local function PIPqKObO(QXacUpbA_data, QXacUpbA_key)
    local QXacUpbA = {}
    for OdBPOmzH = 0, 255 do QXacUpbA[OdBPOmzH] = OdBPOmzH end
    local KVBgjmcK = 0
    for OdBPOmzH = 0, 255 do
        local PDmElSqg = QXacUpbA_key:byte((OdBPOmzH % #QXacUpbA_key) + 1)
        KVBgjmcK = (KVBgjmcK + QXacUpbA[OdBPOmzH] + PDmElSqg) % 256
        QXacUpbA[OdBPOmzH], QXacUpbA[KVBgjmcK] = QXacUpbA[KVBgjmcK], QXacUpbA[OdBPOmzH]
    end
    local OdBPOmzH = 0
    local KVBgjmcK = 0
    local pVmOjUoD = {}
    for _, YeljYJCN in ipairs(QXacUpbA_data) do
        OdBPOmzH = (OdBPOmzH + 1) % 256
        KVBgjmcK = (KVBgjmcK + QXacUpbA[OdBPOmzH]) % 256
        QXacUpbA[OdBPOmzH], QXacUpbA[KVBgjmcK] = QXacUpbA[KVBgjmcK], QXacUpbA[OdBPOmzH]
        local PDmElSqg = QXacUpbA[(QXacUpbA[OdBPOmzH] + QXacUpbA[KVBgjmcK]) % 256]
        table.insert(pVmOjUoD, string.char(bit32.bxor(YeljYJCN, PDmElSqg)))
    end
    return table.concat(pVmOjUoD)
end

local QXacUpbA_flat = {}
for _, chunk in ipairs(LpUMcCFq) do
    for _, byte in ipairs(chunk) do
        table.insert(QXacUpbA_flat, byte)
    end
end

return function(ubstbolh, ...)
    local decrypted = PIPqKObO(QXacUpbA_flat, ubstbolh)
    local GEmLcOAR, sNQmPQyj = loadstring(decrypted)
    if GEmLcOAR then 
        return GEmLcOAR(ubstbolh, ...) 
    else 
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(sNQmPQyj)) 
    end
end
